public synchronized Result deductStock(Long goodsId, String requestId, int num) {
    // 参数校验
    if (requestId == null || requestId.length() <1 || requestId.length()>64) {
        return Result.fail("请求ID非法");
    }
    if (num < 1) { // 边界判断1
        return Result.fail("扣减数量非法");
    }
    // 幂等校验：先查幂等表
    IdempotentRecord record = idempotentMapper.selectByRequestId(goodsId, requestId);
    if (record != null) {
        return record.getResult(); // 返回之前的结果
    }
    // 扣减库存，执行SQL：update goods set stock = stock - #{num} where id = #{goodsId} and stock >= #{num}
    int updateRows = stockMapper.deductStock(goodsId, num);
    if (updateRows > 0) {
        // 扣减成功，插入幂等记录
        IdempotentRecord newRecord = new IdempotentRecord();
        newRecord.setGoodsId(goodsId);
        newRecord.setRequestId(requestId);
        newRecord.setResult(Result.success());
        idempotentMapper.insert(newRecord);
        return Result.success();
    } else {
        // 扣减失败，插入幂等记录
        IdempotentRecord newRecord = new IdempotentRecord();
        newRecord.setGoodsId(goodsId);
        newRecord.setRequestId(requestId);
        newRecord.setResult(Result.fail("库存不足"));
        idempotentMapper.insert(newRecord);
        return Result.fail("库存不足");
    }
}
