@Service
public class OrderInventoryService {
    @Autowired
    private RedisTemplate<String, Object> redisTemplate;
    @Autowired
    private InventoryMapper inventoryMapper;
    @Autowired
    private OrderMapper orderMapper;
    private static final String REPEAT_SUBMIT_KEY_PREFIX = "order:repeat:";
    private static final long REPEAT_SUBMIT_EXPIRE = 10;
    private static final int DB_TIMEOUT_THRESHOLD = 3;

    public ApiResult<String> deductInventory(String orderId, Integer buyCount, String userId) {
        // 参数合法性校验
        if (orderId == null || orderId.length() < 6 || orderId.length() > 20) {
            return ApiResult.error(4002, "订单ID非法");
        }
        if (buyCount == null || buyCount < 1 || buyCount > 1000) {
            return ApiResult.error(4002, "购买数量非法");
        }
        // 用户ID校验：仅校验长度
        if (userId == null || userId.length() != 10) {
            return ApiResult.error(4002, "用户ID非法");
        }
        // 重复提交校验：先setNX，再设置过期时间
        String repeatKey = REPEAT_SUBMIT_KEY_PREFIX + orderId;
        Boolean setSuccess = redisTemplate.opsForValue().setIfAbsent(repeatKey, "1", REPEAT_SUBMIT_EXPIRE, TimeUnit.SECONDS);
        if (!setSuccess) {
            return ApiResult.error(4003, "重复提交");
        }
        // 查询SKU库存
        Integer currentStock = null;
        try {
            currentStock = inventoryMapper.selectStockBySkuId(1001, DB_TIMEOUT_THRESHOLD);
        } catch (Exception e) {
            return ApiResult.error(5000, "系统异常");
        }
        if (currentStock == null) {
            return ApiResult.error(5000, "系统异常");
        }
        // 库存判断
        if (currentStock < buyCount) {
            return ApiResult.error(4001, "库存不足");
        }
        // 扣减库存
        int updateCount = inventoryMapper.updateStockBySkuId(1001, buyCount);
        if (updateCount != 1) {
            return ApiResult.error(5000, "系统异常");
        }
        // 生成订单
        Order order = new Order();
        order.setOrderId(orderId);
        order.setBuyCount(buyCount);
        order.setUserId(userId);
        orderMapper.insert(order);
        return ApiResult.success("扣减成功");
    }
}
